export const toolFaqFr: Record<string, FAQItem[]> = {
  "merge": [
    { question: "Comment fusionner plusieurs PDF en un seul fichier ?", answer: "Ajoutez les fichiers PDF que vous souhaitez combiner, puis faites-les glisser dans l'ordre de votre choix. Une fois organisés, l'outil les assemble en un seul document tout en conservant les polices, la mise en page et la mise en forme d'origine de chaque fichier. Téléchargez le résultat fusionné immédiatement." },
    { question: "Puis-je réorganiser les PDF avant de les fusionner ?", answer: "Oui. Avant la fusion, vous pouvez faire glisser chaque fichier dans l'ordre de votre choix afin que le document final respecte exactement la séquence souhaitée. C'est pratique pour regrouper des chapitres, des factures ou des contrats qui doivent apparaître dans un agencement précis." },
    { question: "Y a-t-il une limite au nombre de PDF que je peux combiner ?", answer: "Vous pouvez fusionner autant de fichiers PDF que nécessaire en un seul document. Comme tout s'exécute localement dans votre navigateur en utilisant la mémoire de votre propre appareil, les très grands lots dépendent des ressources disponibles sur votre ordinateur plutôt que d'une limite serveur fixe." },
    { question: "Mes fichiers sont-ils envoyés quelque part lorsque je les fusionne ?", answer: "Non. Toute la fusion se déroule directement dans votre navigateur, vos PDF ne quittent donc jamais votre appareil et ne transitent par aucun serveur. Cela garde des documents sensibles comme les contrats et les rapports financiers totalement privés et confidentiels tout au long du processus." },
    { question: "L'outil Fusionner PDF est-il gratuit ?", answer: "Totalement gratuit, sans inscription ni compte requis. Vous pouvez combiner un nombre illimité de PDF aussi souvent que vous le souhaitez, sans frais, et aucun filigrane n'est ajouté à votre document fusionné." },
  ],
  "split": [
    { question: "Comment diviser un PDF en fichiers séparés ?", answer: "Chargez votre PDF et choisissez une méthode de division : plages de pages personnalisées, nombre de pages fixe, ou division toutes les N pages. L'outil divise alors le document en fichiers plus petits instantanément, chacun conservant le texte, les images et la qualité de mise en forme d'origine." },
    { question: "Quelles méthodes de division cet outil prend-il en charge ?", answer: "Vous pouvez diviser par plages de pages personnalisées pour extraire des sections précises, par nombre de pages fixe par fichier, ou toutes les N pages. Cette flexibilité vous permet de découper un long rapport en chapitres ou d'extraire exactement les pages dont vous avez besoin." },
    { question: "La division peut-elle m'aider à respecter les limites de taille des pièces jointes ?", answer: "Oui. Découper un grand PDF en fichiers plus petits est un moyen courant de faire entrer des documents dans les limites de taille des e-mails ou des téléversements. Divisez le fichier en morceaux gérables, puis envoyez chaque partie séparément sans perdre en qualité." },
    { question: "La division réduira-t-elle la qualité de mon PDF ?", answer: "Non. Chaque fichier résultant conserve la même netteté du texte, les mêmes images et la même mise en forme que le PDF source. L'opération de division sépare simplement les pages au lieu de les recompresser, de sorte que chaque résultat correspond à la qualité du document original." },
    { question: "Mes documents sont-ils envoyés lorsque je divise un PDF ?", answer: "Jamais. La division complète s'exécute dans votre navigateur, votre fichier reste donc sur votre appareil tout au long. Rien n'est envoyé à un serveur, ce qui garde les contenus confidentiels ou sensibles entièrement privés." },
  ],
  "delete-pages": [
    { question: "Comment supprimer des pages d'un PDF ?", answer: "Sélectionnez les pages dont vous voulez vous débarrasser, et l'outil crée un nouveau PDF sans elles tout en conservant le reste de votre contenu intact. Vous pouvez retirer une seule page, plusieurs pages ou des plages entières en une seule opération, puis télécharger le fichier nettoyé." },
    { question: "Puis-je supprimer plusieurs pages à la fois ?", answer: "Oui. Vous pouvez supprimer des pages individuelles, plusieurs pages dispersées ou des plages de pages entières en une seule action. Cela permet de retirer rapidement les pages blanches, les sections inutiles ou les contenus confidentiels avant de partager le document." },
    { question: "La suppression de pages modifiera-t-elle mon fichier original ?", answer: "Non. Le processus est non destructif, votre PDF source reste donc intact jusqu'à ce que vous téléchargiez la version modifiée. Vous travaillez toujours sur une copie, ce qui vous permet d'expérimenter librement sans risquer le document d'origine." },
    { question: "La suppression de pages affecte-t-elle la qualité du reste ?", answer: "Pas du tout. Chaque page restante conserve sa mise en forme, ses images et la qualité de son texte d'origine. La suppression de pages ne retire que celles que vous sélectionnez, laissant le contenu restant exactement tel qu'il apparaissait dans le PDF source." },
    { question: "La suppression de pages de documents sensibles est-elle privée ?", answer: "Oui. Tout le traitement se déroule localement dans votre navigateur, les fichiers contenant des informations confidentielles ne sont donc jamais envoyés à un serveur. Cela rend sûr le retrait de pages privées de contrats, de rapports ou de documents numérisés sur votre propre appareil." },
  ],
  "extract-pages": [
    { question: "Comment extraire des pages précises d'un PDF ?", answer: "Choisissez les pages que vous voulez, et l'outil crée un nouveau PDF contenant uniquement ces pages. Vous pouvez extraire une seule page, plusieurs pages ou des plages complètes, puis télécharger un document ciblé qui inclut exactement le contenu que vous avez sélectionné." },
    { question: "Les pages extraites conserveront-elles un texte sélectionnable et indexable ?", answer: "Oui. L'outil préserve les polices, la mise en page, les images et le texte d'origine, de sorte que les pages extraites sont identiques à la source. Le texte reste entièrement indexable et sélectionnable, ce qui est utile lorsque vous extrayez des chapitres ou des sections de rapport à réutiliser plus tard." },
    { question: "Quelle est la différence entre extraire et diviser des pages ?", answer: "L'extraction ne réunit que les pages que vous choisissez dans un nouveau document, idéale pour constituer un fichier ciblé à partir de pages dispersées. La division répartit un PDF en plusieurs fichiers séparés. Utilisez l'extraction lorsque vous voulez un unique recueil personnalisé de pages précises." },
    { question: "Puis-je extraire des pages non consécutives dans un seul document ?", answer: "Oui. Vous pouvez sélectionner des pages individuelles provenant de différentes parties du PDF ainsi que des plages continues, et elles sont combinées dans un seul nouveau fichier. C'est idéal pour assembler un document personnalisé à partir des sections pertinentes uniquement." },
    { question: "Mes fichiers sont-ils en sécurité lors de l'extraction de pages ?", answer: "Absolument. L'extraction s'exécute entièrement dans votre navigateur, vos documents ne quittent donc jamais votre appareil et ne sont envoyés nulle part. Vous pouvez extraire en toute sécurité des pages de rapports confidentiels ou de manuels en sachant que rien n'est transmis à un serveur." },
  ],
  "reorder": [
    { question: "Comment réorganiser les pages d'un PDF ?", answer: "Ouvrez votre PDF pour voir les aperçus en miniature de chaque page, puis faites glisser n'importe quelle page vers une nouvelle position. La disposition visuelle facilite le repérage et le déplacement des bonnes pages, et vous pouvez prévisualiser le nouvel ordre avant de télécharger." },
    { question: "Puis-je déplacer plusieurs pages ensemble lors de la réorganisation ?", answer: "Oui. Vous pouvez faire glisser les pages une à une ou sélectionner plusieurs pages et les déplacer en groupe. Cela accélère les réorganisations plus importantes, comme déplacer une section entière d'un rapport vers un autre endroit du document." },
    { question: "L'outil affiche-t-il les miniatures des pages pendant la réorganisation ?", answer: "Oui. Chaque page apparaît sous forme d'aperçu en miniature, de sorte que vous pouvez voir clairement ce que vous déplacez et confirmer l'agencement visuellement. Cela rend la correction d'un scan mal ordonné ou la restructuration du contenu bien plus facile qu'en travaillant uniquement avec des numéros de page." },
    { question: "La réorganisation des pages dégradera-t-elle la qualité du document ?", answer: "Non. Le réagencement des pages préserve toute la mise en forme, les images et la qualité du texte de l'original. L'outil ne modifie que l'ordre des pages, de sorte que chaque page conserve toute sa netteté et reste indexable dans le document réorganisé." },
    { question: "La réorganisation se fait-elle en privé dans mon navigateur ?", answer: "Oui. Tout le processus de glisser-déposer se déroule localement sur votre appareil, sans aucun fichier envoyé à un serveur. Vos documents restent privés, ce qui rend sûr le réagencement de PDF sensibles ou confidentiels." },
  ],
  "rotate": [
    { question: "Comment faire pivoter les pages d'un PDF ?", answer: "Choisissez les pages que vous voulez tourner et sélectionnez une rotation de 90, 180 ou 270 degrés. Vous pouvez faire pivoter tout à la fois ou corriger uniquement les pages dont l'orientation est incorrecte, puis télécharger le document corrigé immédiatement." },
    { question: "Puis-je faire pivoter une seule page plutôt que tout le PDF ?", answer: "Oui. L'outil vous permet de faire pivoter des pages précises individuellement, de sorte que vous pouvez corriger uniquement celles capturées sous le mauvais angle tout en laissant toutes les autres pages exactement telles quelles. C'est idéal pour corriger des erreurs de numérisation isolées." },
    { question: "Quels angles de rotation sont disponibles ?", answer: "Vous pouvez faire pivoter les pages de 90, 180 ou 270 degrés. Ces options couvrent les corrections d'orientation courantes, qu'une page numérisée soit arrivée de travers, à l'envers, ou qu'elle doive être tournée pour répondre à une exigence précise de visualisation ou d'impression." },
    { question: "La rotation affecte-t-elle la qualité du texte ou des images ?", answer: "Non. La rotation préserve toute la qualité du contenu, y compris le texte, les images et la mise en forme. Le texte pivoté reste indexable et sélectionnable, de sorte que le document conserve toutes ses fonctionnalités et reste aussi net qu'avant, seulement sous l'angle corrigé." },
    { question: "Mes fichiers sont-ils envoyés lorsque je fais pivoter des pages ?", answer: "Non. La rotation se déroule instantanément dans votre navigateur, vos documents ne quittent donc jamais votre appareil. Ce traitement local garde les documents numérisés ou les fichiers privés totalement confidentiels pendant que vous corrigez leur orientation." },
  ],
  "insert-blank": [
    { question: "Comment insérer des pages blanches dans un PDF ?", answer: "Indiquez où vous voulez placer les pages vierges et combien en ajouter. L'outil insère des pages blanches au début, à la fin ou entre n'importe quelles pages existantes, puis vous permet de télécharger le document mis à jour immédiatement." },
    { question: "Où puis-je ajouter des pages blanches dans mon document ?", answer: "Vous pouvez les insérer tout au début, à la fin ou entre deux pages existantes quelconques. Il vous suffit de choisir la position exacte et le nombre de pages à ajouter, ce qui vous donne un contrôle total sur l'endroit où le nouvel espace apparaît." },
    { question: "Quelle sera la taille des pages blanches insérées ?", answer: "Les pages blanches s'adaptent automatiquement à la taille et à l'orientation des pages existantes de votre document. Cela garde le fichier cohérent pour l'impression ou la reliure, de sorte que l'espace ajouté s'intègre parfaitement au reste de votre PDF." },
    { question: "Pourquoi ajouterais-je des pages blanches à un PDF ?", answer: "Les raisons courantes incluent laisser de la place pour des notes manuscrites, créer des sauts de page pour l'impression, préparer un document pour la reliure, ou réserver des emplacements pour du contenu que vous ajouterez plus tard. L'outil rend chacune de ces opérations rapide à mettre en place." },
    { question: "L'insertion de pages blanches est-elle gratuite et privée ?", answer: "Oui sur les deux points. L'outil est gratuit sans inscription, et tout le traitement s'exécute localement dans votre navigateur. Votre fichier n'est jamais envoyé à un serveur, le document reste donc privé du début à la fin." },
  ],
  "duplicate-pages": [
    { question: "Comment dupliquer des pages au sein d'un PDF ?", answer: "Sélectionnez les pages que vous voulez copier et choisissez où les doublons doivent aller. L'outil crée des copies exactes et les place à la position que vous indiquez, puis vous permet de télécharger le document mis à jour immédiatement." },
    { question: "Puis-je dupliquer plus d'une page à la fois ?", answer: "Oui. Vous pouvez copier une seule page ou plusieurs pages en une seule opération, et déposer les doublons n'importe où dans le document. C'est pratique pour répéter un formulaire à remplir ou une page modèle plusieurs fois sans copier-coller manuel." },
    { question: "Les pages dupliquées sont-elles des copies exactes des originales ?", answer: "Oui. Chaque doublon préserve toute la mise en forme, les images, le texte et les éléments visuels de la page source, de sorte que la copie est identique en apparence et en fonctionnalité. Rien n'est perdu ni altéré pendant la duplication." },
    { question: "Où puis-je placer les pages dupliquées ?", answer: "Vous pouvez positionner les copies à n'importe quel endroit de votre document, pas seulement à côté des originales. Cela vous permet de constituer un PDF avec des formulaires, des modèles ou des pages de secours répétés disposés exactement là où vous en avez besoin." },
    { question: "La duplication de pages garde-t-elle mes fichiers privés ?", answer: "Oui. Toute la duplication s'exécute dans votre navigateur, vos documents ne quittent donc jamais votre appareil et n'atteignent aucun serveur. Vous pouvez copier des pages de formulaires ou de modèles sensibles en toute confidentialité et sécurité." },
  ],
  "reverse-order": [
    { question: "Comment inverser l'ordre des pages de mon PDF ?", answer: "Importez votre PDF et l'outil inverse instantanément l'intégralité de la séquence des pages : la dernière page devient la première et la première devient la dernière. Il n'y a rien à configurer. Une fois l'ordre inversé, vous pouvez télécharger le nouveau PDF immédiatement." },
    { question: "L'inversion de l'ordre va-t-elle modifier le contenu ou la qualité de mes pages ?", answer: "Non. Seule la séquence des pages change. Chaque page conserve exactement son texte, ses images, sa mise en forme et sa résolution d'origine. Les pages elles-mêmes ne sont pas modifiées, simplement réorganisées de la dernière à la première, de sorte que la qualité reste identique à celle de votre fichier source." },
    { question: "Puis-je corriger un PDF numérisé à l'envers avec cet outil ?", answer: "Oui, c'est un usage courant. Si votre scanner a capturé les pages dans l'ordre inverse, cet outil rétablit en un clic toute la séquence dans le bon ordre, du début à la fin, ce qui vous évite de réorganiser chaque page manuellement." },
    { question: "L'outil d'inversion de l'ordre des pages est-il gratuit ?", answer: "Entièrement gratuit, sans inscription requise. Vous pouvez inverser autant de PDF que vous le souhaitez, sans aucun frais. Aucun filigrane n'est ajouté et aucun compte n'est à créer avant de télécharger votre document inversé." },
    { question: "Mes fichiers restent-ils confidentiels lors de l'inversion de l'ordre des pages ?", answer: "Oui. Tout le traitement s'effectue localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Votre document reste entièrement sur votre appareil tout au long de l'inversion, ce qui préserve la confidentialité totale de vos fichiers sensibles." },
  ],
  "split-by-size": [
    { question: "Comment fonctionne la division d'un PDF par taille de fichier ?", answer: "Vous définissez une limite de taille maximale, et l'outil analyse votre PDF puis le divise à des endroits pertinents afin que chaque fichier généré reste en dessous de cette limite. Importez votre document, choisissez la taille cible et téléchargez les fichiers plus petits obtenus." },
    { question: "Quelles unités de taille puis-je définir comme limite ?", answer: "Vous pouvez indiquer votre maximum en KB, MB ou GB, ce qui offre un contrôle précis sur la taille des fichiers générés. Il est ainsi facile de respecter les limites des pièces jointes d'e-mail, les restrictions de stockage cloud ou toute exigence de taille de fichier propre à une plateforme." },
    { question: "Puis-je télécharger tous les fichiers divisés en une seule fois ?", answer: "Oui. Après la division, vous pouvez récupérer chaque fichier individuellement ou les télécharger ensemble dans une seule archive ZIP, ce qui est pratique lorsque votre PDF est divisé en plusieurs parties." },
    { question: "Chaque fichier divisé conservera-t-il la même qualité que l'original ?", answer: "Chaque fichier généré conserve toute la mise en forme, les images et la qualité du texte de votre document source. L'outil se contente de répartir le contenu en fichiers plus petits pour respecter votre limite de taille ; il ne compresse ni ne dégrade en aucune façon les pages." },
    { question: "Est-il sûr de diviser des documents confidentiels par taille ?", answer: "Oui. Toute la division s'effectue dans votre navigateur, sur votre propre appareil, votre PDF n'est donc jamais envoyé nulle part. Même les fichiers volumineux ou sensibles restent confidentiels, ce qui est rassurant lors de la préparation de fichiers à envoyer par e-mail ou à partager." },
  ],
  "split-by-bookmarks": [
    { question: "Comment l'outil de division par signets détermine-t-il où diviser mon PDF ?", answer: "L'outil lit la structure de signets ou de chapitres existante de votre PDF et le divise à ces emplacements, transformant chaque section de signet en un fichier distinct. Vous choisissez le niveau de signet auquel diviser, afin que les divisions correspondent au plan de votre document." },
    { question: "Puis-je choisir le niveau de signet auquel diviser ?", answer: "Oui. L'outil détecte tous les signets et vous permet de sélectionner le niveau, qu'il s'agisse des chapitres de premier niveau, des sous-sections ou d'une imbrication plus profonde. Cette flexibilité vous permet de découper un document en quelques grands chapitres ou en de nombreuses parties plus petites." },
    { question: "Que se passe-t-il si mon PDF n'a pas de signets ?", answer: "Cet outil s'appuie sur une structure de signets existante pour déterminer les points de division ; il fonctionne donc mieux avec les PDF qui possèdent déjà des chapitres ou un plan, comme les manuels, les ouvrages scolaires ou les documents juridiques. Sans signets, il n'y a aucun repère sur lequel diviser." },
    { question: "Les signets sont-ils conservés dans les fichiers obtenus ?", answer: "Oui. Chaque fichier divisé conserve les signets qu'il contient, ainsi que toute la mise en forme, les images et la qualité du texte de l'original. Les chapitres restent navigables, de sorte que votre structure organisée est reportée dans les documents plus petits." },
    { question: "Mes fichiers restent-ils confidentiels lors de la division par signets ?", answer: "Absolument. Tout le traitement s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Vos documents structurés restent sur votre appareil, et vous pouvez télécharger les fichiers divisés individuellement ou dans une seule archive ZIP." },
  ],
  "sign": [
    { question: "Comment puis-je ajouter ma signature à un PDF ?", answer: "Vous avez trois options : dessiner votre signature à la souris ou au pavé tactile, taper votre nom dans une sélection de polices, ou importer une image de votre signature existante. Placez-la ensuite où vous voulez sur n'importe quelle page et téléchargez le PDF signé." },
    { question: "Puis-je positionner et redimensionner ma signature sur la page ?", answer: "Oui. L'outil offre un placement flexible, vous permettant de faire glisser votre signature à n'importe quel endroit de n'importe quelle page et de la redimensionner pour l'ajuster. C'est pratique pour les lignes de signature, les paraphes ou pour insérer proprement votre marque dans un champ de formulaire." },
    { question: "La signature est-elle réellement intégrée au document ?", answer: "Oui. Votre signature est intégrée directement dans le PDF et fait partie du document lui-même plutôt que d'être une superposition séparée. Le fichier signé conserve une haute qualité et est prêt à être téléchargé et partagé immédiatement après la signature." },
    { question: "La signature de PDF est-elle ici gratuite et confidentielle ?", answer: "C'est gratuit, sans inscription, et entièrement confidentiel. Tout le traitement s'effectue localement dans votre navigateur, de sorte que les données de votre signature et votre document ne quittent jamais votre appareil. C'est donc parfaitement adapté pour signer des contrats ou des formulaires à distance, sans rien imprimer." },
    { question: "Puis-je signer un PDF sur mon téléphone ou ma tablette ?", answer: "Oui. Comme l'outil fonctionne dans le navigateur, vous pouvez dessiner votre signature directement avec un écran tactile sur mobile ou tablette, ou bien la taper ou l'importer. Cela fonctionne sans installer d'application ni imprimer le document." },
  ],
  "redact": [
    { question: "Le caviardage avec cet outil est-il permanent ?", answer: "Oui. L'outil masque complètement les informations sélectionnées et les supprime, de sorte qu'elles ne peuvent plus être récupérées ni extraites du document par la suite. Cette suppression irréversible est ce qui rend le partage de fichiers sensibles sûr." },
    { question: "Que puis-je caviarder dans mon PDF ?", answer: "Vous pouvez sélectionner des zones ou du texte précis à masquer, ce qui vous donne un contrôle exact sur ce qui est supprimé. Caviardez des mots isolés, des images ou des sections entières, ce qui convient aux documents juridiques, aux dossiers médicaux, aux relevés financiers et à tout ce qui contient des informations personnelles." },
    { question: "En quoi est-ce différent du simple fait de dessiner un rectangle noir sur le texte ?", answer: "Contrairement à une simple superposition, cet outil supprime définitivement les informations sous-jacentes au lieu de simplement les masquer visuellement. Avec un rectangle dessiné, le texte caché peut encore être copié ; ici, le contenu sensible a réellement disparu et est irrécupérable." },
    { question: "Le caviardage réduit-il la qualité du reste du document ?", answer: "Non. Seules les zones caviardées sont supprimées. Tout le contenu visible conserve sa haute qualité, sa mise en forme et sa résolution d'origine. Vous pouvez télécharger le PDF caviardé immédiatement, prêt à être partagé avec les parties sensibles définitivement effacées." },
    { question: "Mes fichiers sont-ils en sécurité pendant le caviardage ?", answer: "Oui. Chaque étape s'effectue localement dans votre navigateur, votre document n'est donc jamais envoyé à un serveur. Les fichiers juridiques, médicaux ou financiers sensibles restent entièrement sur votre appareil tout au long du processus de caviardage, garantissant une confidentialité totale." },
  ],
  "remove-hidden-data": [
    { question: "Que supprime exactement l'outil de nettoyage de PDF de mon fichier ?", answer: "Il supprime les informations sur l'auteur, les dates de création et de modification, les détails du logiciel, les commentaires, les annotations, les données des champs de formulaire, le JavaScript, les fichiers intégrés et autres contenus cachés. Tout ce que vous voyez sur la page reste, tandis que les métadonnées et scripts invisibles sont nettoyés." },
    { question: "Le nettoyage va-t-il changer l'apparence de mon document ?", answer: "Non. Le processus préserve tout le contenu visible, le texte, les images et la mise en forme exactement tels qu'ils apparaissent. Seules les données cachées et potentiellement sensibles sont supprimées, de sorte que le PDF nettoyé est identique tout en ne contenant aucune des métadonnées sous-jacentes." },
    { question: "Pourquoi devrais-je nettoyer un PDF avant de le partager ?", answer: "Les métadonnées cachées peuvent révéler votre nom, le logiciel utilisé, l'historique des modifications ou des scripts intégrés à toute personne qui ouvre le fichier. Le nettoyage empêche cette fuite d'informations, ce qui est important lors de la publication de documents ou de leur envoi à des tiers." },
    { question: "Supprime-t-il aussi le JavaScript et les fichiers intégrés ?", answer: "Oui. Au-delà des métadonnées, l'outil supprime le JavaScript intégré, les fichiers joints et autres contenus potentiellement dangereux, rendant le PDF obtenu plus propre et plus sûr à distribuer, et pas seulement débarrassé des informations sur l'auteur." },
    { question: "Le processus de nettoyage est-il confidentiel ?", answer: "Totalement. Tout le nettoyage s'effectue localement dans votre navigateur, votre document ne quitte donc jamais votre appareil. C'est particulièrement adapté pour un outil de confidentialité, puisque votre fichier n'est envoyé nulle part pendant que ses données cachées sont supprimées." },
  ],
  "certificate": [
    { question: "Quels formats de certificat la signature par certificat prend-elle en charge ?", answer: "Elle fonctionne avec les certificats numériques X.509 standard aux formats .pfx et .p12. Vous pouvez également ajouter des détails comme le motif de la signature et votre lieu, qui sont intégrés au document aux côtés de la signature cryptographique." },
    { question: "En quoi la signature par certificat diffère-t-elle d'une signature ordinaire ?", answer: "Une signature visuelle se contente d'afficher un graphique, tandis qu'un certificat fournit une preuve cryptographique d'identité et d'intégrité du document. Il crée un sceau infalsifiable qui révèle si le fichier a été modifié après la signature, ce qui le rend juridiquement contraignant dans de nombreuses juridictions." },
    { question: "La signature indiquera-t-elle si quelqu'un modifie le document par la suite ?", answer: "Oui. La signature par certificat intègre un sceau infalsifiable dans le PDF. Si le document est modifié après la signature, la signature devient invalide, alertant les destinataires que l'intégrité du fichier a été compromise après votre signature." },
    { question: "Mon certificat et ma clé privée sont-ils en sécurité avec cet outil ?", answer: "Oui. Toute la signature s'effectue localement dans votre navigateur, de sorte que votre certificat et vos clés privées ne quittent jamais votre appareil et ne sont jamais envoyés à un serveur. Vos identifiants sensibles restent ainsi protégés pendant que vous appliquez une signature vérifiée." },
    { question: "Qui devrait utiliser la signature basée sur un certificat ?", answer: "Elle convient à toute personne ayant besoin de signatures vérifiées et juridiquement solides, comme les professionnels du droit signant des contrats, les agents publics traitant des documents officiels, ou les entreprises approuvant des formulaires lorsqu'une preuve cryptographique d'identité et d'intégrité du document est requise." },
  ],
  "pdf-to-images": [
    { question: "Vers quels formats d'image puis-je exporter les pages de mon PDF ?", answer: "Vous pouvez choisir PNG, JPEG ou WebP. Le PNG conserve une qualité parfaite et prend en charge la transparence, le JPEG produit des fichiers plus petits avec une bonne qualité, et le WebP offre une compression moderne avec un excellent rapport qualité/taille pour le web." },
    { question: "Puis-je convertir seulement certaines pages au lieu de tout le PDF ?", answer: "Oui. Vous pouvez sélectionner des pages précises à convertir ou traiter l'ensemble du document en une seule fois. Chaque page devient son propre fichier image distinct, ce qui est utile pour extraire un seul graphique ou générer des miniatures." },
    { question: "Les images converties conserveront-elles la qualité d'origine ?", answer: "Chaque page est rendue à sa résolution d'origine, en préservant le texte, les images, les graphiques et la mise en page. Choisir le PNG offre une qualité sans perte avec transparence, de sorte que les images exportées reproduisent fidèlement l'apparence de chaque page du PDF source." },
    { question: "Comment télécharger plusieurs images converties ?", answer: "Après la conversion, vous pouvez enregistrer chaque image individuellement ou les télécharger toutes ensemble dans une seule archive ZIP. L'option ZIP est pratique lorsque vous avez converti de nombreuses pages et souhaitez les regrouper dans un seul fichier." },
    { question: "Mes PDF restent-ils confidentiels lors de la conversion en images ?", answer: "Oui. Toute la conversion s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Votre document reste sur votre appareil pendant que chaque page est transformée en image PNG, JPEG ou WebP." },
  ],
  "images-to-pdf": [
    { question: "Quels formats d'image puis-je combiner dans un PDF ?", answer: "Vous pouvez déposer des fichiers PNG, JPEG, WebP, GIF et BMP et mélanger librement les formats au sein d'un même document. Les images WebP sont traitées automatiquement en arrière-plan, et chaque image ajoutée devient sa propre page dans le PDF final." },
    { question: "Comment définir l'ordre des images dans mon PDF ?", answer: "Après le téléversement, il vous suffit de glisser-déposer les vignettes pour les organiser à votre guise avant de générer le fichier. Les pages apparaissent exactement dans cet ordre, ce qui facilite la création d'albums photo ou l'assemblage correct de documents numérisés." },
    { question: "Puis-je choisir la taille et l'orientation des pages ?", answer: "Oui. Choisissez A4, Letter, A3, A5 ou une taille personnalisée, optez pour le mode portrait ou paysage, ajoutez des marges et décidez si chaque image s'ajuste à la page ou si la page s'adapte à l'image. Ces options vous permettent d'adapter la mise en page à vos besoins." },
    { question: "Mes images sont-elles téléversées sur un serveur ?", answer: "Non. Tout s'exécute localement dans votre navigateur grâce à la puissance de traitement de votre appareil, de sorte que vos photos et numérisations ne quittent jamais votre ordinateur. Il n'y a aucun téléversement ni aucun compte, ce qui garde vos images personnelles ou sensibles totalement privées." },
    { question: "La conversion réduit-elle la qualité de mes images ?", answer: "Vos images conservent leur résolution et leurs couleurs d'origine une fois placées dans le PDF. Si vous activez l'ajustement à la page, les grandes images sont réduites pour tenir proprement sur la page, mais ne sont jamais agrandies, afin que la netteté et les détails restent intacts dans le document final." },
  ],
  "pdf-to-word": [
    { question: "Le convertisseur conserve-t-il ma mise en forme dans Word ?", answer: "Il reconstruit le document en détectant les lignes et les paragraphes, et reporte les tailles de police et le texte en gras lorsque c'est possible. Des sauts de page sont ajoutés entre les pages afin que le DOCX modifiable reste structurellement proche de la mise en page d'origine du PDF." },
    { question: "Cela fonctionne-t-il sur un PDF numérisé ?", answer: "Les PDF numérisés ou composés uniquement d'images ne contiennent aucun texte sélectionnable à extraire, l'outil ne peut donc pas en récupérer les mots puisqu'il n'exécute pas d'OCR. Il fonctionne mieux sur des PDF qui contiennent déjà un véritable texte lisible par machine plutôt que des images de texte." },
    { question: "Puis-je convertir uniquement certaines pages ?", answer: "Oui. Saisissez une plage de pages comme 1-5, ou une combinaison comme 1,3,7-9, et seules ces pages sont transformées en fichier Word. Laissez le champ vide ou tapez « all » pour convertir l'ensemble du document d'un coup." },
    { question: "La conversion de PDF vers Word est-elle gratuite et privée ?", answer: "Elle est entièrement gratuite, sans inscription, et la conversion se déroule intégralement dans votre navigateur. Votre PDF n'est jamais envoyé à un serveur, ce qui signifie que les contrats confidentiels, rapports ou documents personnels restent sur votre propre appareil." },
    { question: "Quel fichier l'outil produit-il et puis-je l'ouvrir partout ?", answer: "Vous obtenez un fichier .docx standard qui s'ouvre dans Microsoft Word, Google Docs, LibreOffice et la plupart des autres traitements de texte. Une fois téléchargé, vous pouvez modifier, remettre en forme et réutiliser le texte comme n'importe quel document Word classique." },
  ],
  "pdf-to-excel": [
    { question: "Comment l'outil détecte-t-il les tableaux dans mon PDF ?", answer: "L'outil analyse la position de chaque élément de texte, regroupe les éléments d'une même ligne en rangées et aligne les positions horizontales communes en colonnes. Lorsqu'il trouve une grille nette, il construit une véritable feuille de calcul ; sinon, il se rabat sur des rangées ligne par ligne." },
    { question: "Plusieurs pages sont-elles regroupées dans une seule feuille ou réparties sur plusieurs ?", answer: "Chaque page du PDF devient son propre onglet de feuille dans le classeur, étiqueté par numéro de page, et les colonnes sont dimensionnées automatiquement pour une meilleure lisibilité. Cela garde les données de différentes pages séparées et faciles à parcourir dans Excel." },
    { question: "Peut-il extraire des tableaux d'une facture ou d'un rapport numérisé ?", answer: "Uniquement si le PDF contient un véritable texte. Les documents numérisés sont des images, et cet outil n'effectue pas d'OCR, il ne peut donc pas lire les chiffres à partir d'une photo de page. Utilisez des PDF avec un texte réellement sélectionnable pour une extraction précise." },
    { question: "Quel format vais-je obtenir et l'outil est-il gratuit ?", answer: "Vous recevez un fichier .xlsx prêt à l'emploi qui s'ouvre dans Excel, Google Sheets ou LibreOffice Calc, et l'outil est entièrement gratuit, sans compte requis. À partir de là, vous pouvez modifier, trier et appliquer des formules aux données." },
    { question: "Mes données financières sont-elles sécurisées pendant la conversion ?", answer: "Totalement. Toute l'extraction des tableaux s'exécute localement dans votre navigateur, de sorte que les factures, relevés et rapports financiers ne sont jamais téléversés où que ce soit. Vos chiffres sensibles restent sur votre machine, du début jusqu'à la feuille de calcul finale." },
  ],
  "pdf-to-text": [
    { question: "Le texte extrait conserve-t-il l'ordre de lecture d'origine ?", answer: "Oui. L'outil trie le texte selon sa position verticale et horizontale afin que les lignes ressortent de haut en bas et de gauche à droite, comme vous liriez la page. Le résultat est un fichier .txt propre, sans codes de mise en forme ni caractères parasites." },
    { question: "Puis-je extraire le texte de quelques pages seulement ?", answer: "Vous pouvez spécifier une plage de pages comme 2-6 ou une liste comme 1,4,9 pour extraire le texte de ces seules pages. Il existe également une option permettant d'étiqueter chaque page avec son numéro dans le résultat si vous souhaitez des repères de page clairs." },
    { question: "L'outil parviendra-t-il à extraire le texte d'un document numérisé ?", answer: "Les PDF numérisés sont des images de texte, et cet extracteur lit le texte intégré plutôt que d'exécuter un OCR, il ne peut donc pas reconnaître les mots à l'intérieur d'une image. Il excelle sur les PDF numériques qui contiennent déjà un véritable contenu textuel sélectionnable." },
    { question: "L'outil est-il gratuit et téléverse-t-il mon PDF ?", answer: "Il est gratuit, sans inscription, et rien n'est téléversé. L'extraction se déroule directement dans votre navigateur sur votre propre appareil, de sorte que même des travaux de recherche confidentiels ou des documents privés ne transitent jamais par un serveur." },
    { question: "Que puis-je faire du texte brut ensuite ?", answer: "Le résultat en .txt propre est idéal pour l'analyse de texte, l'indexation de recherche, la copie de contenu dans d'autres applications ou l'alimentation de scripts et d'autres outils de traitement. Comme il s'agit de texte brut UTF-8, il fonctionne avec pratiquement n'importe quel éditeur ou programme." },
  ],
  "pdf-to-csv": [
    { question: "Puis-je changer le délimiteur ou le caractère de guillemet dans le CSV ?", answer: "Oui. Vous pouvez définir un délimiteur personnalisé, par exemple un point-virgule au lieu d'une virgule, et choisir le caractère de guillemet utilisé pour entourer les valeurs. Les champs contenant des délimiteurs, des guillemets ou des sauts de ligne sont échappés automatiquement afin que le CSV s'importe proprement." },
    { question: "L'outil crée-t-il un seul CSV ou un fichier distinct par page ?", answer: "C'est vous qui décidez. Par défaut, toutes les pages sont combinées dans un seul CSV avec des repères de page, ou vous pouvez activer des fichiers distincts par page. Lorsqu'il y a plusieurs fichiers, ils sont regroupés dans un ZIP pour un téléchargement unique." },
    { question: "Dans quelle mesure gère-t-il les tableaux à plusieurs colonnes ?", answer: "L'outil cartographie la position de chaque élément de texte pour détecter les rangées et les colonnes, puis aligne les cellules dans une grille structurée. Il fonctionne mieux sur des tableaux clairement disposés ; les pages au formatage approximatif peuvent se rabattre sur un résultat plus simple, rangée par rangée." },
    { question: "Cela fonctionne-t-il sur un tableau de PDF numérisé ?", answer: "Non, car les pages numérisées sont des images et l'outil lit le texte intégré sans OCR. Pour un résultat CSV fiable, utilisez des PDF qui contiennent un véritable texte sélectionnable plutôt que des tableaux photographiés ou numérisés." },
    { question: "Est-ce gratuit et mes données restent-elles privées ?", answer: "Le convertisseur est gratuit, sans compte, et tout le traitement reste dans votre navigateur sur votre appareil. Vos données tabulaires ne sont jamais téléversées, de sorte que les tableaux financiers ou de recherche restent confidentiels pendant que vous les transformez en CSV." },
  ],
  "pdf-to-html": [
    { question: "Puis-je inclure des images dans le résultat HTML ?", answer: "Il existe une option pour intégrer directement les images sous forme de données base64, afin que le HTML soit autonome et ne dépende pas de fichiers image séparés. Vous pouvez aussi laisser les images de côté pour obtenir une page plus légère et axée sur le texte lorsque cela vous convient mieux." },
    { question: "Puis-je appliquer mon propre CSS à la page convertie ?", answer: "Oui. Vous pouvez fournir des styles CSS personnalisés pour contrôler l'apparence du HTML généré, ce qui vous permet de l'accorder au design ou à la mise en forme de votre site. Le résultat s'ouvre dans n'importe quel navigateur et peut être peaufiné davantage dans n'importe quel éditeur HTML." },
    { question: "Quelles pages sont converties en HTML ?", answer: "Par défaut, l'ensemble du document est converti, mais vous pouvez saisir une plage de pages comme 1-4 ou une liste comme 2,5,8 pour ne transformer que les pages sélectionnées en HTML. C'est pratique lorsque vous n'avez besoin que d'une partie d'un long PDF en ligne." },
    { question: "La conversion est-elle gratuite et reste-t-elle sur mon appareil ?", answer: "Elle est gratuite, sans inscription, et toute la conversion s'exécute localement dans votre navigateur. Votre PDF n'est jamais envoyé où que ce soit, de sorte que même des documents non publiés ou sensibles restent privés pendant que vous les préparez pour le web." },
    { question: "Que puis-je faire du fichier HTML ensuite ?", answer: "Le résultat est un fichier HTML prêt pour le web que vous pouvez publier en ligne, intégrer à un site ou ouvrir dans n'importe quel navigateur. Les caractères spéciaux sont correctement échappés, de sorte que le balisage est propre et prêt à être édité davantage dans vos outils." },
  ],
  "pdf-to-markdown": [
    { question: "Détecte-t-il automatiquement les titres ?", answer: "Oui. Le convertisseur analyse le texte et peut marquer les titres probables avec la syntaxe de titre Markdown, ce qui aide à préserver la hiérarchie du document. Le résultat est ainsi prêt à être intégré dans une documentation ou un blog avec sa structure intacte." },
    { question: "Comment les caractères spéciaux sont-ils gérés dans le Markdown ?", answer: "Les caractères qui ont une signification en Markdown, comme les astérisques, les traits de soulignement, les crochets et les accents graves, sont échappés afin de s'afficher en texte brut au lieu de casser la mise en forme. Votre contenu converti reste ainsi correctement rendu partout où vous le collez." },
    { question: "Puis-je convertir uniquement certaines pages en Markdown ?", answer: "Vous pouvez saisir une plage de pages comme 1-3 ou une liste comme 2,4,6 pour ne convertir que ces pages. Laisser le champ vide ou saisir « all » traite l'ensemble du document en un seul fichier Markdown." },
    { question: "Est-ce gratuit et mon PDF est-il téléversé où que ce soit ?", answer: "L'outil est gratuit, sans compte requis, et la conversion se déroule intégralement dans votre navigateur. Rien n'est téléversé sur un serveur, de sorte que la documentation technique ou les brouillons que vous n'êtes pas prêt à partager restent entièrement sur votre propre appareil." },
    { question: "Pourquoi utiliser le Markdown plutôt qu'un autre format ?", answer: "Le Markdown est du texte brut, le résultat est donc léger, facile à modifier dans n'importe quel éditeur et fonctionne sans accroc avec les systèmes de gestion de versions comme Git. Cela en fait un format idéal pour la documentation, la rédaction technique et les articles de blog." },
  ],
  "compress": [
    { question: "De combien l'outil peut-il réduire mon PDF ?", answer: "Les économies dépendent du contenu du fichier et du niveau de qualité que vous choisissez. L'outil restructure le PDF à l'aide de flux d'objets et peut supprimer les métadonnées, ce qui réduit la surcharge. Les documents riches en images et alourdis en profitent généralement le plus." },
    { question: "La compression va-t-elle rendre mon texte ou mes images flous ?", answer: "Le texte reste net et interrogeable car il n'est pas rastérisé. Vous choisissez un niveau de qualité, du plus bas au plus élevé, pour équilibrer la taille du fichier et la fidélité, afin de privilégier des fichiers plus petits ou de préserver davantage de détails selon le document." },
    { question: "Puis-je supprimer les métadonnées pour rendre le fichier plus petit et plus propre ?", answer: "Oui. Il existe une option pour supprimer les métadonnées telles que le titre, l'auteur et les mots-clés, ce qui réduit légèrement la taille et élimine des détails personnels cachés. C'est utile avant de partager un document que vous préférez ne pas voir associé à vos informations." },
    { question: "Y a-t-il une limite de taille de fichier ?", answer: "Il n'y a pas de plafond fixe côté serveur, car la compression s'exécute localement dans votre navigateur. La limite pratique dépend de la mémoire disponible de votre appareil, de sorte que les très gros fichiers fonctionnent, mais peuvent prendre plus de temps sur des machines moins puissantes." },
    { question: "Mes documents sont-ils privés lorsque je les compresse ?", answer: "Totalement. Aucun fichier n'est téléversé sur un serveur ; toute l'optimisation se déroule sur votre propre appareil. Cela rend l'outil sûr pour compresser des rapports ou contrats confidentiels que vous devez envoyer par e-mail ou archiver sans les exposer en ligne." },
  ],
  "add-watermark": [
    { question: "Comment ajouter un filigrane à mon PDF ?", answer: "Importez votre PDF, puis choisissez un filigrane texte ou image et ajustez son emplacement, son opacité, sa rotation, sa taille et sa couleur. Vous pouvez l'apposer sur chaque page ou en sélectionner certaines. Lorsque l'aperçu vous convient, téléchargez le fichier filigrané directement depuis votre navigateur." },
    { question: "Puis-je utiliser le logo de mon entreprise comme filigrane image ?", answer: "Oui. En plus des filigranes texte comme Confidentiel ou Brouillon, vous pouvez importer une image, comme le logo de votre entreprise, et la superposer sur les pages. Ajustez sa taille, son opacité et sa rotation pour que la marque reste discrète en arrière-plan ou apparaisse bien visible et au premier plan." },
    { question: "Puis-je apposer un filigrane uniquement sur certaines pages plutôt que sur tout le document ?", answer: "Absolument. Vous n'êtes pas obligé de tout filigraner. Sélectionnez des pages précises pour recevoir le filigrane tout en laissant les autres intactes, ou appliquez-le uniformément sur l'ensemble du document pour une image de marque cohérente sur vos rapports, propositions et autres fichiers multipages." },
    { question: "L'ajout d'un filigrane réduira-t-il la qualité de mon PDF ?", answer: "Non. Le filigrane est superposé à vos pages tandis que le texte, les images et la mise en forme d'origine restent intacts en dessous. Le PDF obtenu conserve sa haute qualité, et vous pouvez contrôler l'opacité pour que le marquage protège votre travail sans masquer le contenu." },
    { question: "L'outil de filigrane est-il gratuit et mes documents restent-ils confidentiels ?", answer: "Il est entièrement gratuit et ne nécessite aucune inscription. Chaque étape s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Vos contrats, propositions et fichiers confidentiels sensibles restent entièrement sur votre appareil tout au long du processus." },
  ],
  "page-numbers": [
    { question: "Comment ajouter des numéros de page à un PDF ?", answer: "Ouvrez votre PDF, choisissez l'endroit où les numéros doivent figurer, puis téléchargez le résultat. Vous pouvez les placer en haut ou en bas et à gauche, au centre ou à droite, avec un contrôle sur la police, la taille et le numéro de départ pour s'accorder au style de votre document." },
    { question: "Puis-je choisir où apparaissent les numéros de page et à quel numéro commencer ?", answer: "Oui. Vous décidez de la position, en haut ou en bas et aligné à gauche, au centre ou à droite, et vous pouvez définir un numéro de départ personnalisé. C'est pratique lorsqu'une partie liminaire ou une page de couverture fait que la première page ne doit pas être la première à être numérotée." },
    { question: "Puis-je ignorer la numérotation sur la page de couverture ou certaines pages ?", answer: "Oui. L'outil vous permet d'appliquer la numérotation à l'ensemble du document ou d'ignorer des pages sélectionnées, comme les pages de couverture ou de titre, afin que seules les pages souhaitées portent un numéro, ce qui est idéal pour les rapports et les thèses." },
    { question: "Puis-je personnaliser la police et la taille des numéros de page ?", answer: "Tout à fait. Au-delà du positionnement, vous pouvez ajuster la police et la taille des numéros pour qu'ils s'harmonisent avec la typographie de votre document, gardant ainsi les travaux universitaires, les documents juridiques et les manuels imprimés cohérents et professionnels." },
    { question: "Est-ce gratuit et mes fichiers restent-ils confidentiels ?", answer: "L'ajout de numéros de page est gratuit et ne nécessite aucun compte. Tout le traitement s'effectue localement dans votre navigateur, ce qui signifie que votre PDF n'est jamais envoyé à un serveur. Vos mémoires, contrats et rapports restent confidentiels sur votre propre machine." },
  ],
  "crop": [
    { question: "Comment recadrer les pages d'un PDF ?", answer: "Chargez votre PDF et définissez visuellement les limites de recadrage dans l'interface pour supprimer les marges ou les bordures. Appliquez le même recadrage à chaque page ou ajustez les pages individuellement, puis téléchargez le document épuré une fois qu'il vous convient." },
    { question: "Puis-je recadrer chaque page différemment ou uniquement toutes les pages de la même façon ?", answer: "Les deux options sont disponibles. Vous pouvez appliquer un recadrage uniforme sur l'ensemble du document pour aller plus vite, ou ajuster finement chaque page lorsque les numérisations présentent des marges irrégulières, ce qui vous offre de la flexibilité pour un matériau source mixte ou inégal." },
    { question: "Le recadrage supprimera-t-il du texte ou des images à l'intérieur de mes pages ?", answer: "Non. Le recadrage supprime uniquement la zone située en dehors des limites que vous avez choisies. Tout le texte, les images et la mise en forme à l'intérieur de la région conservée sont préservés exactement, vous éliminez donc les espaces blancs ou les bords noirs du scanner sans perdre de contenu essentiel." },
    { question: "Puis-je utiliser l'outil de recadrage pour supprimer les bords noirs du scanner et les marges ?", answer: "Oui, c'est l'un de ses usages principaux. Il est idéal pour couper les bordures noires laissées par les scanners, supprimer les espaces blancs superflus autour des documents numérisés et recentrer les pages sur le contenu important, pour une impression plus nette et une lecture à l'écran plus facile." },
    { question: "Le recadrage est-il gratuit et mes fichiers sont-ils envoyés quelque part ?", answer: "L'outil de recadrage est gratuit et ne nécessite aucune inscription. Rien n'est envoyé ; l'ensemble du processus s'exécute localement dans votre navigateur, de sorte que vos livres numérisés, documents privés et tout PDF sensible ne quittent jamais votre appareil." },
  ],
  "resize": [
    { question: "Comment changer le format de page d'un PDF ?", answer: "Importez votre PDF et choisissez un préréglage comme A4 ou Letter, ou saisissez une largeur et une hauteur personnalisées. L'outil adapte votre contenu aux nouvelles dimensions tout en conservant les proportions, puis vous permet de télécharger le fichier redimensionné." },
    { question: "Vers quels formats et tailles de page puis-je redimensionner ?", answer: "Vous pouvez sélectionner des préréglages courants comme A4 et Letter, ou spécifier vos propres dimensions personnalisées. Cela facilite la conversion entre les standards de papier régionaux ou l'adaptation des pages à une exigence de mise en page particulière pour l'impression ou le partage." },
    { question: "Le redimensionnement déformera-t-il ou étirera-t-il mon contenu ?", answer: "Non. Lors de l'adaptation des pages à de nouvelles dimensions, l'outil préserve les proportions afin que le texte et les images restent proportionnés et lisibles plutôt qu'étirés. Le résultat conserve sa qualité, prêt pour les imprimeries ou les travaux normalisés." },
    { question: "Puis-je uniformiser un document comportant des tailles de page différentes ?", answer: "Oui. Si vous avez des pages numérisées de tailles variables ou un document mélangeant les formats, vous pouvez toutes les redimensionner à une taille cohérente, ce qui est idéal avant d'envoyer des fichiers à une imprimerie ou pour unifier un PDF compilé." },
    { question: "L'outil de redimensionnement est-il gratuit et confidentiel ?", answer: "Il est gratuit et sans inscription. Tout le redimensionnement s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Vos documents restent confidentiels sur votre appareil du début à la fin." },
  ],
  "grayscale": [
    { question: "Comment convertir un PDF en niveaux de gris ?", answer: "Importez simplement votre PDF en couleur et l'outil convertit automatiquement chaque page en noir et blanc. Le texte, les images et les graphiques en couleur deviennent des nuances de gris harmonieuses, et vous pouvez télécharger le document monochrome final immédiatement." },
    { question: "La conversion en niveaux de gris réduit-elle la taille du fichier PDF ?", answer: "Souvent, oui. Supprimer les informations de couleur des images et des graphiques peut réduire la taille du fichier, ce qui est utile pour l'envoi par e-mail, l'archivage ou le téléversement de documents. La conversion crée aussi un rendu plus uniforme tout en gardant les détails nets." },
    { question: "Mon texte et mes images resteront-ils nets après la conversion en niveaux de gris ?", answer: "Oui. L'outil convertit les couleurs en nuances de gris harmonieuses tout en préservant la netteté et les détails de votre texte, de vos images et de vos graphiques, de sorte que le résultat reste propre et lisible plutôt que délavé ou flou." },
    { question: "Le niveau de gris est-il utile pour réduire les coûts d'impression ?", answer: "Tout à fait. Convertir en noir et blanc avant l'impression vous permet d'éviter d'utiliser de l'encre couleur sur de longs documents, ce qui fait des économies. C'est un choix populaire pour imprimer des rapports et des supports de façon économique ou archiver des fichiers dans un format monochrome cohérent." },
    { question: "L'outil de niveaux de gris est-il gratuit et mes fichiers sont-ils sécurisés ?", answer: "La conversion en niveaux de gris est gratuite et ne nécessite aucun compte. Tout se passe localement dans votre navigateur, aucun fichier n'est donc envoyé à un serveur. Vos documents restent totalement confidentiels sur votre propre appareil tout au long du processus." },
  ],
  "invert-colors": [
    { question: "Comment inverser les couleurs d'un PDF pour le mode sombre ?", answer: "Importez votre PDF et lancez l'inversion en une seule opération. Les arrière-plans blancs deviennent sombres et le texte noir devient clair sur toutes les pages, produisant instantanément une version au thème sombre que vous pouvez télécharger pour une lecture à l'écran confortable." },
    { question: "Le texte restera-t-il sélectionnable après l'inversion des couleurs ?", answer: "Oui. L'inversion change les couleurs tout en gardant le texte net, lisible et entièrement sélectionnable, de sorte que le document reste fonctionnel. Vous pouvez toujours rechercher, surligner et copier le texte comme avant la transformation." },
    { question: "Cela crée-t-il une véritable expérience de lecture en mode sombre ?", answer: "Oui. En rendant sombres les arrière-plans d'un blanc éclatant et en plaçant un texte clair par-dessus, il produit un PDF au thème sombre confortable qui réduit la fatigue oculaire lors des lectures tardives ou des longues sessions à l'écran en faible luminosité." },
    { question: "Puis-je inverser les couleurs de tout le document en une seule fois ?", answer: "Oui. Une seule opération applique l'inversion à chaque page sur l'ensemble du document, il n'est donc pas nécessaire d'ajuster les pages une par une. Vous obtenez un fichier entièrement au thème sombre, prêt pour la lecture à l'écran en quelques secondes." },
    { question: "L'inversion des couleurs est-elle gratuite et mes fichiers restent-ils confidentiels ?", answer: "L'outil est gratuit et ne nécessite aucune inscription. Tout le traitement s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé où que ce soit. Vos supports d'étude et vos documents restent confidentiels sur votre appareil." },
  ],
  "flatten": [
    { question: "Comment aplatir un PDF ?", answer: "Importez votre PDF et l'outil fusionne les champs de formulaire, les annotations et les éléments interactifs directement dans le contenu statique des pages. Les champs à remplir, les cases à cocher, les commentaires et les annotations deviennent partie intégrante de la page, et vous pouvez télécharger le fichier verrouillé immédiatement." },
    { question: "Qu'advient-il de mes champs de formulaire remplis lorsque j'aplatis ?", answer: "Ils sont verrouillés définitivement dans la page. Après l'aplatissement, les cases à cocher, les champs de texte et les autres saisies deviennent partie intégrante du contenu statique, de sorte que les destinataires ne peuvent pas modifier les données. C'est idéal pour finaliser des formulaires remplis avant de les partager ou pour archiver des documents signés." },
    { question: "Pourquoi aplatir un PDF avant de le partager ?", answer: "L'aplatissement empêche les destinataires de modifier les données saisies et garantit que le document s'affiche de manière cohérente sur tous les lecteurs et imprimantes PDF. C'est parfait pour soumettre des formulaires officiels ou distribuer des fichiers infalsifiables, prêts à imprimer, qui doivent s'afficher exactement comme prévu." },
    { question: "L'aplatissement verrouille-t-il aussi les commentaires et annotations dans la page ?", answer: "Oui. Au-delà des champs de formulaire, les annotations telles que les commentaires et les marquages sont également fusionnés dans le contenu de la page, de sorte que le résultat visible est préservé exactement, sans qu'aucune couche modifiable ne subsiste par-dessus le document." },
    { question: "L'outil d'aplatissement est-il gratuit et mes données sont-elles sécurisées ?", answer: "L'aplatissement est gratuit et ne nécessite aucun compte. Tout le traitement s'effectue localement dans votre navigateur, vos formulaires remplis et documents signés ne sont donc jamais envoyés à un serveur. Vos données sensibles restent confidentielles sur votre appareil." },
  ],
  "remove-annotations": [
    { question: "Comment supprimer les annotations d'un PDF ?", answer: "Importez votre PDF et l'outil détecte et supprime chaque couche d'annotation sur toutes les pages en une seule opération. Les commentaires, les surlignages, les notes autocollantes et les marquages sont supprimés, laissant un document propre que vous pouvez télécharger immédiatement." },
    { question: "Quels types de marquages cet outil supprime-t-il ?", answer: "Il efface les commentaires, les surlignages, les notes autocollantes et les autres marquages ajoutés lors de la relecture ou de la collaboration. Chaque couche d'annotation est détectée et supprimée d'un coup, produisant une version soignée et sans distraction, débarrassée de tout encombrement éditorial." },
    { question: "La suppression des annotations modifiera-t-elle le texte ou les images d'origine ?", answer: "Non. Seules les couches d'annotation sont supprimées. Le texte, les images et la mise en forme sous-jacents sont préservés exactement tels qu'ils apparaissent, vous obtenez donc une copie propre sans altérer le contenu réel du document." },
    { question: "Puis-je effacer toutes les notes des relecteurs en une seule fois avant publication ?", answer: "Oui. L'outil supprime chaque annotation sur toutes les pages en une seule opération, ce qui le rend parfait pour effacer les retours des relecteurs d'un brouillon finalisé ou pour produire une copie propre et professionnelle d'un manuscrit fortement annoté." },
    { question: "La suppression des annotations est-elle gratuite et mes fichiers restent-ils confidentiels ?", answer: "L'outil est gratuit et sans inscription. Tout le traitement s'exécute localement dans votre navigateur, votre PDF n'est donc jamais envoyé à un serveur. Vos documents relus et vos brouillons restent confidentiels sur votre propre appareil." },
  ],
  "extract-images": [
    { question: "Comment extraire des images d'un PDF avec cet outil ?", answer: "Importez votre PDF, et l'outil analyse chaque page à la recherche d'images intégrées pour les extraire automatiquement. Vous pouvez extraire les images de toutes les pages ou définir une plage de pages, puis télécharger les résultats. Aucune sélection manuelle ni capture d'écran n'est nécessaire durant le processus." },
    { question: "Dans quels formats puis-je enregistrer les images extraites ?", answer: "Vous pouvez exporter les images extraites au format PNG ou JPEG. Le PNG préserve une qualité sans perte, tandis que le JPEG vous permet de définir un niveau de qualité de compression pour des fichiers plus légers. Choisissez le format qui convient le mieux à l'usage que vous comptez faire des images par la suite." },
    { question: "Puis-je télécharger toutes les images extraites en une seule fois ?", answer: "Oui. Lorsqu'un PDF contient plusieurs images, l'outil les regroupe dans une seule archive ZIP afin que vous puissiez tout récupérer en un clic. Chaque fichier est nommé d'après sa page source, ce qui garde vos images extraites organisées et faciles à trier par la suite." },
    { question: "Les images extraites conserveront-elles leur qualité d'origine ?", answer: "L'outil extrait les images matricielles intégrées au plus près de leur résolution d'origine, afin que les photos et les graphiques restent nets. Le choix du PNG les conserve sans perte, tandis que la qualité JPEG est ajustable. Notez que les illustrations purement vectorielles ne sont pas des images en pixels et peuvent ne pas être extraites en tant que fichiers distincts." },
    { question: "Mes fichiers PDF sont-ils envoyés quelque part lorsque j'extrais des images ?", answer: "Non. Toute l'extraction s'exécute localement dans votre navigateur en utilisant les ressources de votre propre appareil. Votre PDF n'est jamais envoyé à un serveur, de sorte que vos rapports sensibles, contrats ou documents personnels restent entièrement confidentiels tout au long du processus. L'outil est également gratuit." },
  ],
  "remove-images": [
    { question: "La suppression des images efface-t-elle le texte de mon PDF ?", answer: "Non. L'outil supprime les objets image intégrés tout en laissant intacts votre texte, vos graphiques vectoriels et la mise en page. Le contenu écrit reste entièrement lisible et consultable, vous obtenez donc un document propre axé sur le texte plutôt qu'un fichier amputé ou corrompu." },
    { question: "La suppression des images réduira-t-elle la taille de mon fichier PDF ?", answer: "Généralement oui, et souvent de manière spectaculaire. Les images constituent en général la partie la plus lourde d'un PDF, donc les supprimer peut réduire considérablement un rapport volumineux. Cela rend le document bien plus facile à envoyer par e-mail, à téléverser sur des portails ayant des limites de taille, ou à stocker sans occuper trop d'espace." },
    { question: "L'outil supprime-t-il les images de toutes les pages en une seule fois ?", answer: "Oui. En une seule opération, il analyse toutes les pages et supprime les XObjects d'images intégrées, les images en ligne et les opérateurs qui les dessinent. Vous n'avez pas besoin de procéder page par page ; l'ensemble du document est traité en un seul passage pour un résultat homogène." },
    { question: "Cet outil est-il gratuit et dois-je créer un compte ?", answer: "Il est entièrement gratuit, sans inscription, sans connexion ni filigrane. Ouvrez simplement l'outil, déposez votre PDF et téléchargez la version sans images. Il n'y a aucune limite d'utilisation ni paywall caché bloquant le résultat une fois le traitement terminé." },
    { question: "Mes documents sont-ils en sécurité lorsque je supprime des images ?", answer: "Tout se passe localement dans votre navigateur, votre PDF n'est donc jamais téléversé sur un serveur. Vos fichiers confidentiels restent sur votre propre appareil du début à la fin, ce qui rend l'outil particulièrement adapté aux contrats sensibles, aux rapports financiers et aux documents privés." },
  ],
  "optimize-images": [
    { question: "Comment cet outil réduit-il la taille de mon fichier PDF ?", answer: "Il localise les images intégrées dans votre PDF, réduit la taille de celles qui sont plus grandes que nécessaire et les recompresse avec des réglages efficaces. Comme les images sont généralement la partie la plus volumineuse d'un document, cela produit habituellement un fichier bien plus léger tout en gardant des pages bien nettes." },
    { question: "Puis-je contrôler la qualité et la résolution des images ?", answer: "Oui. Vous pouvez définir un niveau de qualité de compression JPEG ainsi qu'une résolution maximale pour le plus grand côté de chaque image. Des réglages plus bas réduisent le fichier plus agressivement, tandis que des réglages plus élevés préservent davantage de détails, vous permettant d'équilibrer la taille et la netteté visuelle." },
    { question: "L'optimisation va-t-elle dégrader les images transparentes ou les logos ?", answer: "Non. L'outil détecte les images avec transparence et les ré-encode en PNG pour préserver le canal alpha, tandis que les photos opaques sont compressées en JPEG pour un gain maximal. Les logos transparents et les superpositions conservent leurs zones translucides au lieu de se retrouver avec un arrière-plan plein." },
    { question: "Qu'advient-il des formats d'image que l'outil ne peut pas traiter ?", answer: "Certains formats spécialisés, comme certains flux CMYK, JBIG2 ou JPEG2000, ne peuvent pas être ré-encodés dans le navigateur. L'outil ignore simplement ces images et continue d'optimiser les autres, de sorte que la tâche se termine avec succès au lieu d'échouer sur une image non prise en charge." },
    { question: "L'optimisation se fait-elle de manière confidentielle dans mon navigateur ?", answer: "Oui. Toute la réduction de taille et la compression s'exécutent localement sur votre appareil, et rien n'est téléversé sur un serveur. Votre PDF reste confidentiel, ce qui est idéal pour alléger des rapports ou des présentations confidentiels avant de les envoyer par e-mail, le tout entièrement gratuitement." },
  ],
  "add-qr-code": [
    { question: "Que puis-je encoder dans le QR code que j'ajoute ?", answer: "Vous pouvez encoder n'importe quelle URL de site web ou du texte brut, comme une coordonnée de contact, un message promotionnel ou un lien de téléchargement. Une fois scanné, le code ouvre le lien ou affiche votre texte. C'est pratique pour les flyers, les brochures, les factures et les billets d'événement." },
    { question: "Puis-je choisir l'emplacement du QR code sur la page ?", answer: "Oui. Vous définissez à la fois la position et la taille du QR code, afin qu'il se trouve exactement où vous le souhaitez. Vous pouvez également cibler une page précise ou une plage de pages plutôt que de l'apposer sur l'ensemble du document." },
    { question: "Le QR code restera-t-il scannable de façon fiable une fois imprimé ?", answer: "Oui. Le code est rendu nettement à une résolution élevée en pixels avec une correction d'erreurs intégrée, de sorte qu'il reste scannable aussi bien à l'écran que sur papier. Le conserver à une taille raisonnable sur la page aide les caméras à le détecter rapidement." },
    { question: "Comment ajouter un QR code à mon PDF ?", answer: "Importez votre PDF, saisissez l'URL ou le texte que vous souhaitez encoder, puis positionnez et dimensionnez le code sur la page de votre choix. L'outil le génère et le place instantanément, et vous téléchargez le PDF finalisé immédiatement." },
    { question: "Mon PDF reste-t-il confidentiel lors de l'ajout d'un QR code ?", answer: "Absolument. Le QR code est généré et intégré entièrement au sein de votre navigateur, sans qu'aucun fichier ne quitte votre appareil. Cela garde vos factures, billets et documents internes confidentiels, et l'outil est gratuit, sans inscription requise." },
  ],
  "add-barcode": [
    { question: "Quels formats de codes-barres cet outil prend-il en charge ?", answer: "Vous pouvez générer des codes Code128, Code39, EAN-13, UPC-A, ITF-14 et même des QR codes. Les formats linéaires conviennent à l'étiquetage en commerce de détail et en gestion des stocks, tandis que le QR fonctionne pour des liens ou des données plus longues. Choisissez simplement la symbologie qui correspond à votre scanner ou à votre flux de travail." },
    { question: "L'outil vérifie-t-il que les données de mon code-barres sont valides ?", answer: "Oui. Les formats numériques sont validés avant la génération : ainsi l'EAN-13 attend 12 ou 13 chiffres, l'UPC-A en requiert 11 ou 12, et l'ITF-14 en exige 13 ou 14. Si les données ne correspondent pas au format choisi, vous obtiendrez une erreur plutôt qu'un code non scannable." },
    { question: "Puis-je placer le code-barres exactement où j'en ai besoin sur la page ?", answer: "Vous contrôlez la position, la largeur et la hauteur du code-barres, et vous pouvez l'appliquer à une page précise ou à une plage de pages. Cela permet d'aligner le code proprement avec la disposition de votre étiquette, de votre étiquette de prix ou de votre bordereau d'expédition plutôt qu'il n'atterrisse à un emplacement fixe." },
    { question: "Le code-barres se scannera-t-il correctement en caisse ou en entrepôt ?", answer: "Oui. Chaque code-barres est rendu à une résolution nette et prête à l'impression, avec la valeur lisible affichée en dessous. Ce rendu net est conçu pour un scan fiable aussi bien à l'écran que sur des étiquettes imprimées, aux comptoirs de caisse comme dans les opérations logistiques." },
    { question: "L'ajout d'un code-barres est-il gratuit et confidentiel ?", answer: "C'est gratuit, sans compte requis, et le code-barres est créé directement dans votre navigateur. Votre PDF et vos données produit ne touchent jamais un serveur, de sorte que vos fiches de stock et catalogues restent confidentiels pendant que vous produisez des documents scannables en interne." },
  ],
  "add-bookmarks": [
    { question: "En quoi les signets aident-ils les lecteurs à naviguer dans mon PDF ?", answer: "Les signets créent un plan cliquable qui apparaît dans la barre latérale des lecteurs PDF standard. Le lecteur clique sur une entrée pour accéder directement à la page concernée, ce qui rend les longs rapports, livres numériques et manuels bien plus faciles à parcourir que de faire défiler page par page." },
    { question: "Puis-je créer des signets imbriqués ou à plusieurs niveaux ?", answer: "Oui. L'outil prend en charge les signets hiérarchiques, vous pouvez donc imbriquer des sous-entrées sous les chapitres principaux pour construire une table des matières structurée. Chaque signet pointe vers une page précise, offrant à votre document une arborescence de navigation propre et organisée dans le panneau du lecteur." },
    { question: "Puis-je modifier ou remplacer des signets qui existent déjà ?", answer: "Vous pouvez ajouter de nouvelles entrées et reconstruire le plan du document. Par défaut, l'outil remplace le plan existant par la structure que vous définissez, vous permettant de réorganiser un ensemble de signets désordonné ou obsolète en un plan nouveau et précis pour vos lecteurs." },
    { question: "Où apparaissent les signets une fois que je les ai ajoutés ?", answer: "Ils apparaissent dans la barre latérale des signets ou du plan de n'importe quel lecteur PDF standard, y compris Acrobat, Aperçu et la plupart des navigateurs. Les lecteurs ouvrent ce panneau pour voir votre table des matières complète et accéder instantanément à n'importe quelle section." },
    { question: "Mes fichiers sont-ils confidentiels lorsque j'ajoute des signets ?", answer: "Oui. Le plan est écrit dans votre PDF localement dans votre navigateur, sans aucun téléversement vers un serveur. Votre document reste sur votre appareil tout du long, et l'outil est gratuit, sans inscription ni filigrane." },
  ],
  "add-hyperlinks": [
    { question: "Quels types de liens puis-je ajouter à mon PDF ?", answer: "Vous pouvez ajouter des liens web cliquables utilisant des adresses http ou https, ainsi que des liens mailto pour les adresses e-mail. Les domaines simples comme example.com sont automatiquement convertis en URL https complète, afin que les lecteurs puissent cliquer directement sur les citations, références ou coordonnées." },
    { question: "Puis-je afficher un texte de lien visible par-dessus la zone liée ?", answer: "Oui. Chaque lien peut inclure un libellé optionnel dessiné en bleu à l'intérieur du rectangle du lien, de sorte que la zone cliquable soit clairement visible. Si vous n'indiquez pas de libellé, le lien fonctionne tout de même comme une zone cliquable invisible par-dessus le contenu existant." },
    { question: "Comment positionner un hyperlien sur la page ?", answer: "Vous définissez une zone rectangulaire sur une page précise où se trouve le lien, en réglant son emplacement et sa taille sur cette page. Cela vous permet de placer une zone cliquable avec précision sur un mot, une citation ou une région plutôt que sur l'ensemble de la page." },
    { question: "Les liens resteront-ils cliquables dans d'autres lecteurs PDF ?", answer: "Oui. L'outil ajoute des annotations de lien standard, de sorte que les liens restent entièrement interactifs dans les lecteurs courants comme Acrobat, Aperçu et la plupart des navigateurs. Les destinataires peuvent cliquer dessus pour ouvrir la page web cible ou démarrer un e-mail sans aucune étape supplémentaire." },
    { question: "Mon PDF est-il téléversé lorsque j'ajoute des hyperliens ?", answer: "Non. Les liens sont intégrés localement dans votre navigateur, et votre fichier ne quitte jamais votre appareil. Cela garde confidentiels vos rapports et brochures riches en références, et l'outil est entièrement gratuit, sans compte ni filigrane sur le document finalisé." },
  ],
  "add-attachments": [
    { question: "Quels types de fichiers puis-je intégrer dans un PDF ?", answer: "Vous pouvez intégrer plusieurs fichiers de différents types, tels que des feuilles de calcul, des images, des documents et des fichiers de données brutes. Ils voyagent à l'intérieur du PDF en un seul ensemble, ce qui garde les éléments connexes réunis afin que rien ne soit séparé lorsque vous partagez le document." },
    { question: "Où apparaissent les pièces jointes intégrées pour le destinataire ?", answer: "Elles sont stockées dans le panneau des pièces jointes du PDF, accessible dans les lecteurs standard comme Acrobat qui prennent en charge les fichiers intégrés. Les destinataires ouvrent ce panneau pour consulter ou enregistrer chaque fichier joint. Les pages visibles de votre document restent inchangées par l'intégration." },
    { question: "L'intégration de fichiers modifie-t-elle l'apparence des pages de mon PDF ?", answer: "Non. Les pièces jointes sont ajoutées à la structure de fichiers interne du document, et non dessinées sur les pages, de sorte que votre mise en page, votre texte et votre mise en forme restent exactement tels qu'ils étaient. Les fichiers supplémentaires voyagent discrètement sans rien modifier de ce que les lecteurs voient à l'écran." },
    { question: "Pourquoi intégrer des fichiers plutôt que de les envoyer séparément ?", answer: "Regrouper tout dans un seul PDF garde les éléments connexes organisés et évite que les fichiers de support ne se perdent en chemin. C'est utile pour associer une feuille de calcul à un rapport financier, joindre des preuves à un dossier juridique, ou expédier des données sources avec un article de recherche." },
    { question: "Est-ce gratuit et mes fichiers restent-ils confidentiels ?", answer: "Oui pour les deux. L'intégration se fait localement dans votre navigateur, sans aucun téléversement vers un serveur, de sorte que vos dossiers et jeux de données confidentiels restent sur votre appareil. L'outil est gratuit, sans inscription, sans connexion ni filigrane." },
  ],
};
